-- Subtopic 1: Basic Synonyms (30Q) - 12 easy, 12 medium, 6 hard
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "happy":', '["Joyful", "Sad", "Angry", "Tired"]', 0, 'Synonym: Joyful means the same as happy - both describe a state of pleasure or contentment. Sad, angry, and tired are different emotions.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "big":', '["Large", "Small", "Tiny", "Little"]', 0, 'Synonym: Large means the same as big - both describe something of great size. Small, tiny, and little mean the opposite.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "easy":', '["Simple", "Hard", "Difficult", "Complex"]', 0, 'Synonym: Simple means the same as easy - both describe something not complicated. Hard, difficult, and complex are opposites.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "fast":', '["Quick", "Slow", "Lazy", "Tired"]', 0, 'Synonym: Quick means the same as fast - both describe high speed. Slow is the opposite, lazy and tired are different concepts.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "smart":', '["Clever", "Stupid", "Dull", "Foolish"]', 0, 'Synonym: Clever means the same as smart - both describe intelligence. Stupid, dull, and foolish are opposites.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "beautiful":', '["Pretty", "Ugly", "Plain", "Dull"]', 0, 'Synonym: Pretty means the same as beautiful - both describe attractiveness. Ugly, plain, and dull are opposites.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "small":', '["Little", "Big", "Large", "Huge"]', 0, 'Synonym: Little means the same as small - both describe something of modest size. Big, large, and huge are opposites.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "scared":', '["Afraid", "Brave", "Bold", "Confident"]', 0, 'Synonym: Afraid means the same as scared - both describe fear. Brave, bold, and confident are opposites.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "angry":', '["Mad", "Happy", "Calm", "Peaceful"]', 0, 'Synonym: Mad means the same as angry - both describe irritation or rage. Happy, calm, and peaceful are opposite emotions.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "sad":', '["Unhappy", "Joyful", "Cheerful", "Merry"]', 0, 'Synonym: Unhappy means the same as sad - both describe a negative emotional state. Joyful, cheerful, and merry are opposites.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "rich":', '["Wealthy", "Poor", "Broke", "Needy"]', 0, 'Synonym: Wealthy means the same as rich - both describe having much money. Poor, broke, and needy are opposites.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "cold":', '["Chilly", "Hot", "Warm", "Boiling"]', 0, 'Synonym: Chilly means the same as cold - both describe low temperature. Hot, warm, and boiling describe heat.', 'easy'),

