('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "begin":', '["Start", "End", "Finish", "Complete"]', 0, 'Synonym: Start means the same as begin - both describe commencing an action. End, finish, and complete are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "correct":', '["Right", "Wrong", "Incorrect", "False"]', 0, 'Synonym: Right means the same as correct - both indicate accuracy or truth. Wrong, incorrect, and false are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "difficult":', '["Hard", "Easy", "Simple", "Effortless"]', 0, 'Synonym: Hard means the same as difficult - both describe something challenging. Easy, simple, and effortless are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "glad":', '["Pleased", "Upset", "Disappointed", "Sad"]', 0, 'Synonym: Pleased means the same as glad - both express happiness or satisfaction. Upset, disappointed, and sad are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "thin":', '["Slim", "Fat", "Thick", "Wide"]', 0, 'Synonym: Slim means the same as thin - both describe a small width. Fat, thick, and wide are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "quiet":', '["Silent", "Loud", "Noisy", "Booming"]', 0, 'Synonym: Silent means the same as quiet - both describe absence of noise. Loud, noisy, and booming are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "strong":', '["Powerful", "Weak", "Feeble", "Frail"]', 0, 'Synonym: Powerful means the same as strong - both describe great physical or mental force. Weak, feeble, and frail are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "clean":', '["Spotless", "Dirty", "Filthy", "Messy"]', 0, 'Synonym: Spotless means the same as clean - both describe being free from dirt. Dirty, filthy, and messy are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "kind":', '["Gentle", "Cruel", "Mean", "Harsh"]', 0, 'Synonym: Gentle means the same as kind - both describe being considerate and caring. Cruel, mean, and harsh are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "funny":', '["Amusing", "Boring", "Dull", "Serious"]', 0, 'Synonym: Amusing means the same as funny - both describe something that makes you laugh. Boring, dull, and serious are opposites.', 'medium'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "important":', '["Significant", "Trivial", "Minor", "Unimportant"]', 0, 'Synonym: Significant means the same as important - both describe something of great value or meaning. Trivial, minor, and unimportant are opposites.', 'medium'),

('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "enormous":', '["Gigantic", "Tiny", "Miniature", "Minuscule"]', 0, 'Synonym: Gigantic means the same as enormous - both describe something extremely large. Tiny, miniature, and minuscule are opposites.', 'hard'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "ancient":', '["Old", "Modern", "New", "Recent"]', 0, 'Synonym: Old means the same as ancient - both describe something from long ago. Modern, new, and recent are opposites.', 'hard'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "pleasant":', '["Agreeable", "Unpleasant", "Horrible", "Terrible"]', 0, 'Synonym: Agreeable means the same as pleasant - both describe something enjoyable. Unpleasant, horrible, and terrible are opposites.', 'hard'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "polite":', '["Courteous", "Rude", "Impolite", "Disrespectful"]', 0, 'Synonym: Courteous means the same as polite - both describe good manners. Rude, impolite, and disrespectful are opposites.', 'hard'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "genuine":', '["Real", "Fake", "False", "Artificial"]', 0, 'Synonym: Real means the same as genuine - both describe something authentic. Fake, false, and artificial are opposites.', 'hard'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the word that means the same as "entire":', '["Complete", "Partial", "Incomplete", "Fragmented"]', 0, 'Synonym: Complete means the same as entire - both describe something whole. Partial, incomplete, and fragmented are opposites.', 'hard'),

