('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "hot":', '["Cold", "Warm", "Cool", "Mild"]', 0, 'Antonym: Cold is the opposite of hot - they represent extreme opposite temperatures. Warm and cool are moderate temperatures.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "up":', '["Down", "Above", "Over", "High"]', 0, 'Antonym: Down is the opposite of up - they represent opposite vertical directions. Above, over, and high are similar to up.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "good":', '["Bad", "Great", "Excellent", "Fine"]', 0, 'Antonym: Bad is the opposite of good - they represent opposite quality levels. Great, excellent, and fine are similar to good.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "day":', '["Night", "Morning", "Evening", "Afternoon"]', 0, 'Antonym: Night is the opposite of day - they represent opposite times of 24 hours. Morning, evening, and afternoon are parts of the day.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "old":', '["New", "Ancient", "Aged", "Elderly"]', 0, 'Antonym: New is the opposite of old - they represent opposite ages. Ancient, aged, and elderly are similar to old.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "front":', '["Back", "Forward", "Ahead", "Before"]', 0, 'Antonym: Back is the opposite of front - they represent opposite positions. Forward, ahead, and before are similar to front.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "open":', '["Closed", "Wide", "Broad", "Unlocked"]', 0, 'Antonym: Closed is the opposite of open - they represent opposite states. Wide, broad, and unlocked are similar to open.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "left":', '["Right", "Center", "Middle", "Side"]', 0, 'Antonym: Right is the opposite of left - they represent opposite horizontal directions. Center and middle are between left and right.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "full":', '["Empty", "Filled", "Complete", "Packed"]', 0, 'Antonym: Empty is the opposite of full - they represent opposite states of capacity. Filled, complete, and packed are similar to full.', 'easy'),
('foundation', 'synonyms-antonyms', 'beginner', 'Choose the opposite of "high":', '["Low", "Tall", "Elevated", "Above"]', 0, 'Antonym: Low is the opposite of high - they represent opposite vertical positions. Tall, elevated, and above are similar to high.', 'easy'),
